    std::uint64_t aWandererJ = *pWandererJ;
    std::uint64_t aWandererK = *pWandererK;
    std::uint64_t aNonceWordA = TwistMix64::DiffuseB(pNonce * 0xC6B3F90F7E7A39C3ULL + 0x829C9F4E3E48E609ULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseB(pNonce * 0xA11B39AF3B113C17ULL + 0xB54461362B43BC75ULL);
