    std::uint64_t aNonceWordG = TwistMix64::DiffuseA(pNonce * 0x9A23C6EDDEB87AAFULL + 0x9D30965F68708268ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseB(pNonce * 0xFD82E0E506994F6BULL + 0x861E3947C9ECFA82ULL);
