    std::uint64_t aNonceWordJ = TwistMix64::DiffuseB(pNonce * 0x97F0513ED480AB57ULL + 0xDEC5683C445CA735ULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseC(pNonce * 0xAA88A115CB513389ULL + 0xF0308683F84FFEC8ULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseC(pNonce * 0x8FE7074A48AAC729ULL + 0xE8B0C3137140DF1CULL);
