            //
            aCross = (RotL64(aFireLaneC[((S_BLOCK1 - aIndex + 3988U)) & S_BLOCK1], 35U) ^ RotL64(aFireLaneD[((S_BLOCK1 - aIndex + 4226U)) & S_BLOCK1], 23U));
