            //
            aOrbiterI = (aWandererJ + RotL64(aPrevious, 29U)) + 0xB20CA604AB709AA6ULL;
            aOrbiterG = ((aWandererI + RotL64(aScatter, 3U)) + 0xC2E4B093039F492AULL) + aNonceWordL;
            aOrbiterD = (((aWandererE + RotL64(aIngress, 13U)) + RotL64(aCarry, 5U)) + 0x961698879BBBB6B3ULL) + aNonceWordI;
            aOrbiterF = (((aWandererC + RotL64(aCross, 24U)) + 0x065EA26875EA0282ULL) + aPhaseEOrbiterAssignSaltF[(((31U - aIndex) + 24U)) & S_SALT1]) + aNonceWordF;
