            aOrbiterK = (((aWandererD + RotL64(aCross, 43U)) + RotL64(aCarry, 39U)) + 0x4C857EB793E75E67ULL) + aPhaseFOrbiterAssignSaltE[(((31U - aIndex) + 29U)) & S_SALT1];
            aOrbiterB = (aWandererJ + RotL64(aScatter, 3U)) + 0x0CA857AAF8E2E117ULL;
            aOrbiterH = ((aWandererH + RotL64(aIngress, 10U)) + RotL64(aCarry, 11U)) + 0xF3CAB1723DFB7607ULL;
