            aOrbiterF = RotL64((aOrbiterF * 0x5B16B49DBDCA4719ULL), 47U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterF) + 0xCC2AA3CB7AAF1949ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterD) ^ 0x6C4560897349F4D9ULL;
            aOrbiterK = RotL64((aOrbiterK * 0xA644D8607F052BADULL), 3U);
            //
