            aOrbiterJ = (aWandererI + RotL64(aScatter, 13U)) + 0x346A30B0FEE890CEULL;
            aOrbiterG = ((aWandererE + RotL64(aCross, 53U)) + 0xE21B080D4BDFD22CULL) + aPhaseCOrbiterAssignSaltF[((aIndex + 25U)) & S_SALT1];
            aOrbiterE = (aWandererJ + RotL64(aIngress, 19U)) + 0xC8368EA117DAC7D7ULL;
            aOrbiterF = (((aWandererD + RotL64(aPrevious, 29U)) + RotL64(aCarry, 35U)) + 0xD1017773DD9057E6ULL) + aPhaseCOrbiterAssignSaltD[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterA = (aWandererF + RotL64(aCross, 41U)) + 0xCDCF651D337EF4AEULL;
            aOrbiterH = ((aWandererB + RotL64(aScatter, 60U)) + RotL64(aCarry, 5U)) + 0x7D4F6641A92AF08FULL;
            aOrbiterI = ((aWandererK + RotL64(aIngress, 47U)) + RotL64(aCarry, 21U)) + 0x0E6D8C899EEEE50AULL;
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterG) + 0xE90EF69CCF9A59B0ULL;
            aOrbiterE = ((aOrbiterE ^ aOrbiterJ) ^ 0x249BBBFB1B53B827ULL) ^ aPhaseCOrbiterUpdateSaltC[(((31U - aIndex) + 18U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 0x44E52046EF46E3F9ULL), 41U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterE) + 0x7D75B6B2D34A4A41ULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterF) ^ 0x7E5DE0D79B2E84E0ULL;
            aOrbiterA = RotL64((aOrbiterA * 0x13530582B08A023FULL), 47U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterH) + 0x2B0564D03D0659EAULL;
