            aOrbiterH = (aOrbiterH + aOrbiterJ) + 0xFA6650A0964F3A4DULL;
            aOrbiterF = ((aOrbiterF ^ aOrbiterH) ^ 0x617ACA5BCD569757ULL) ^ aPhaseCOrbiterUpdateSaltB[(((31U - aIndex) + 7U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0x4A4C0DB1DBD880A5ULL), 27U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterI) + 0x6F05ABF33CFA5DA9ULL) + aPhaseCOrbiterUpdateSaltE[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterH = (aOrbiterH ^ aOrbiterE) ^ 0xC2CA877D6D536B76ULL;
