            //
            aOrbiterI = (aOrbiterI + aOrbiterA) + 0x75D87E0B790911A5ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterI) ^ 0x183BB6F6466BE4A1ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xE605B24546B8EFA9ULL), 5U);
            //
            aIngress = aOrbiterG ^ RotL64(aOrbiterI, 29U);
            aIngress = aIngress + (aOrbiterA ^ RotL64(aOrbiterE, 56U));
            aIngress = aIngress + (aOrbiterF ^ RotL64(aOrbiterH, 5U));
