            aWandererF = aWandererF ^ ((RotL64(aScatter, 60U) + RotL64(aOrbiterG, 47U)) + aOrbiterA);
            aWandererI = aWandererI + (((RotL64(aCross, 37U) + RotL64(aOrbiterH, 21U)) + aOrbiterF) + RotL64(aCarry, 5U));
