            aOrbiterE = ((aOrbiterE + aOrbiterI) + 0x3B9280C6084F6876ULL) + aPhaseFOrbiterUpdateSaltD[((aIndex + 27U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterE) ^ 0xEEC90E7997CBA5D4ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x11A8A9D3E49C6D63ULL), 11U);
