            aOrbiterH = RotL64((aOrbiterH * 0x3B5BA3C6826EE243ULL), 27U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterD) + 0xC2A1BB43AB740A51ULL) + aPhaseFOrbiterUpdateSaltB[((aIndex + 4U)) & S_SALT1];
            aOrbiterA = ((aOrbiterA ^ aOrbiterK) ^ 0x60BCC9564B4EF56EULL) ^ aPhaseFOrbiterUpdateSaltA[(((31U - aIndex) + 12U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0x081C63EBD930FD7DULL), 19U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterG) + 0xAB92F2C4A23E57B0ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterI) ^ 0x72C67AA2D9051E56ULL;
