            //
            aOrbiterH = (aOrbiterH + aOrbiterA) + 0xDD61B3C99841BB08ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterH) ^ 0x3F27B61A4BA46698ULL;
            aOrbiterE = RotL64((aOrbiterE * 0xE9F323B79762081BULL), 3U);
            //
            aIngress = aOrbiterE ^ RotL64(aOrbiterF, 23U);
