            aCross = (RotL64(aWorkLaneC[((S_BLOCK1 - aIndex + 3286U)) & S_BLOCK1], 21U) ^ RotL64(aWorkLaneD[((S_BLOCK1 - aIndex + 481U)) & S_BLOCK1], 46U));
            aCross ^= RotL64(aScrapLaneC[((aIndex + 3946U)) & S_BLOCK1], 57U);
