            //
            aOrbiterI = (aWandererH + RotL64(aPrevious, 27U)) + 0xDEC9064B920F9916ULL;
            aOrbiterC = (aWandererG + RotL64(aIngress, 5U)) + 0x91CC71875A176A3FULL;
            aOrbiterD = (aWandererK + RotL64(aCross, 19U)) + 0xD3BAFEE7493F389DULL;
            aOrbiterA = (aWandererB + RotL64(aScatter, 29U)) + 0x180B9F4A0DC80E29ULL;
            aOrbiterB = ((aWandererF + RotL64(aCross, 37U)) + RotL64(aCarry, 13U)) + 0xA26D67EB24AE76CEULL;
            aOrbiterG = ((aWandererD + RotL64(aIngress, 3U)) + RotL64(aCarry, 35U)) + 0x848C2E9CA8E82ACAULL;
            aOrbiterK = (aWandererJ + RotL64(aScatter, 60U)) + 0x8BABDCE080A5C480ULL;
            aOrbiterF = (aWandererE + RotL64(aPrevious, 13U)) + 0x906C61A1576B69DCULL;
            aOrbiterJ = ((aWandererC + RotL64(aCross, 47U)) + 0x9B5ED132B13797B1ULL) + aPhaseGOrbiterAssignSaltD[((aIndex + 15U)) & S_SALT1];
            aOrbiterE = ((aWandererA + RotL64(aPrevious, 41U)) + RotL64(aCarry, 23U)) + 0x8EDF0CECD281ADDDULL;
            aOrbiterH = ((aWandererI + RotL64(aIngress, 56U)) + 0x1DAD5CB94C726F83ULL) + aPhaseGOrbiterAssignSaltA[(((31U - aIndex) + 23U)) & S_SALT1];
            //
            aOrbiterI = (aOrbiterI + aOrbiterC) + 0x59D18BC68CAEC0E8ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterI) ^ 0xF6B0D333FBC54AADULL;
            aOrbiterD = RotL64((aOrbiterD * 0x823B1EC29E9C9127ULL), 29U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterI) + 0x9AEDB56DB82D925EULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterA) ^ 0x9DB6FDAFA76B2A5AULL;
            aOrbiterB = RotL64((aOrbiterB * 0x1228A03F797E4FBDULL), 27U);
            //
            aOrbiterG = ((aOrbiterG + aOrbiterK) + 0x70E4E048808D0B31ULL) + aPhaseGOrbiterUpdateSaltC[((aIndex + 13U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterG) ^ 0xE0A186B0BCB0D192ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x3A26D50C3EA10F5BULL), 35U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 0xF583285EEDF1B26DULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterF) ^ 0x10701B2DD6A54D3BULL) ^ aPhaseGOrbiterUpdateSaltE[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0x445A2359CE7F170DULL), 19U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 0xC44225568721A701ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterB) ^ 0x2BF1ED599F129678ULL;
            aOrbiterG = RotL64((aOrbiterG * 0xC7F6A7198499F9F1ULL), 39U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterJ) + 0xD9B7E8A98DA34379ULL;
