            aOrbiterC = RotL64((aOrbiterC * 0x8B5B41BD4BB96389ULL), 21U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterE) + 0xB9EB1725756A8439ULL;
            aOrbiterH = ((aOrbiterH ^ aOrbiterC) ^ 0xD03C62572431A7D0ULL) ^ aPhaseGOrbiterUpdateSaltD[(((31U - aIndex) + 29U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 0x4B2D9897BD338725ULL), 11U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterF) + 0xAC214B9F72855388ULL;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterH) ^ 0x7E24338A29D16B42ULL) ^ aPhaseGOrbiterUpdateSaltB[(((31U - aIndex) + 24U)) & S_SALT1];
