            //
            aOrbiterJ = (aOrbiterJ + aOrbiterA) + 0x2A95C150F53ED7F3ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterJ) ^ 0x6A709E4140624870ULL;
