            //
            aOrbiterE = ((aWandererH + RotL64(aPrevious, 53U)) + RotL64(aCarry, 41U)) + 0x10F240A518D6B2A4ULL;
            aOrbiterH = (aWandererK + RotL64(aScatter, 35U)) + 0x953F92BEDC0488F4ULL;
            aOrbiterD = (aWandererE + RotL64(aIngress, 19U)) + 0x4AE02F2C768BC75AULL;
            aOrbiterC = (aWandererB + RotL64(aCross, 10U)) + 0xD4D4339C592E4F3DULL;
            aOrbiterI = (((aWandererD + RotL64(aIngress, 41U)) + RotL64(aCarry, 53U)) + 0x5358FB1A21F77A93ULL) + aPhaseHOrbiterAssignSaltA[((aIndex + 7U)) & S_SALT1];
            aOrbiterG = ((aWandererF + RotL64(aPrevious, 29U)) + 0xE28FA2DC208C6E86ULL) + aPhaseHOrbiterAssignSaltD[(((31U - aIndex) + 29U)) & S_SALT1];
            aOrbiterF = ((aWandererJ + RotL64(aScatter, 47U)) + RotL64(aCarry, 29U)) + 0x7119302997E23DCAULL;
            aOrbiterK = (aWandererC + RotL64(aCross, 4U)) + 0xC7A972C0F86E3BAAULL;
            aOrbiterB = (aWandererG + RotL64(aIngress, 23U)) + 0x72DCD94ACFD7D6B5ULL;
            //
            aOrbiterE = (aOrbiterE + aOrbiterH) + 0x099877EC9B9D9EC8ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterE) ^ 0xDE25AD8A78D94792ULL;
            aOrbiterD = RotL64((aOrbiterD * 0xEB974D98682B9F91ULL), 51U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterD) + 0xD681C5F141E10BD2ULL) + aPhaseHOrbiterUpdateSaltF[((aIndex + 16U)) & S_SALT1];
            aOrbiterI = ((aOrbiterI ^ aOrbiterC) ^ 0x25A4E9D38C9DAC26ULL) ^ aPhaseHOrbiterUpdateSaltC[(((31U - aIndex) + 18U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 0x3D4EFB16A0B2B885ULL), 13U);
            //
            aOrbiterG = ((aOrbiterG + aOrbiterI) + 0x0BA8B6D9C7C4C743ULL) + aPhaseHOrbiterUpdateSaltA[(((31U - aIndex) + 19U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterG) ^ 0x851325C3F705AA22ULL;
            aOrbiterE = RotL64((aOrbiterE * 0xE5273F68A3588951ULL), 57U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterF) + 0x9BE70933FA4C34DFULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterH) ^ 0x451A525DBD7BFAC5ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x6AEF8DB2879D3117ULL), 27U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterC) + 0x159EB0D666B47097ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterK) ^ 0x3089714EA34DD5CEULL;
            aOrbiterG = RotL64((aOrbiterG * 0xE146983875567C5DULL), 5U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterK) + 0x6FCDC23057991741ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterD) ^ 0xAD4818DC878E8814ULL;
            aOrbiterB = RotL64((aOrbiterB * 0xB10BA5ED8B2509B9ULL), 23U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterB) + 0x683E5C4D0DD88CFAULL;
            aOrbiterH = ((aOrbiterH ^ aOrbiterI) ^ 0xDB5A9F559595D112ULL) ^ aPhaseHOrbiterUpdateSaltE[(((31U - aIndex) + 11U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 0x12C0CEDCCB48444BULL), 35U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterG) + 0xC3CECB2BED311076ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterB) ^ 0x6883D9D3DBBE39B1ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x1211613E55962BC1ULL), 47U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterE) + 0x5DC894F2ED910ADDULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterF) ^ 0xAA89A23CBAD0E3D1ULL;
            aOrbiterC = RotL64((aOrbiterC * 0x0DA2EABDA2658101ULL), 41U);
            //
            aIngress = RotL64(aOrbiterE, 35U) ^ aOrbiterG;
